736	    /**
737	     * Calculates "fair" totals with proper rounding and penny distribution to ensure the sum equals the receipt total.
738	     *
739	     * This function addresses the rounding problem: when individual person totals are rounded to 2 decimal places,
740	     * their sum may not equal the original receipt total. This function distributes rounding differences (pennies)
741	     * fairly among people.
742	     *
743	     * **Algorithm:**
744	     * 1. Converts all amounts to integer cents (truncates to avoid double-conversion errors)
745	     * 2. Calculates the rounding gap between the rounded sum and the receipt total
746	     * 3. Sorts people by largest fractional part (those with the most "leftover" cents get priority)
747	     * 4. Distributes extra/missing pennies one at a time, cycling through people
748	     * 5. Converts back to dollars (Decimal instances)
749	     *
750	     * Uses Decimal.js throughout to maintain precision during the rounding and distribution process.
751	     *
752	     * @param receiptTotal - The total receipt amount as a Decimal instance
753	     * @param personTotals - Map of person identifiers to their calculated totals (as Decimal instances)
754	     * @returns A Map where keys are person identifiers and values are "fair" totals as Decimal instances.
755	     *          The sum of these fair totals equals the receipt total (within 1 cent).
756	     *
757	     * @example
758	     * ```ts
759	     * // Receipt total: $31.00
760	     * // Person totals: [10.333, 10.333, 10.334] (sum = 31.00)
761	     * // After rounding: [10.33, 10.33, 10.34] (sum = 31.00) ✓
762	     *
763	     * const receiptTotal = new Decimal(31.00);
764	     * const personTotals = new Map([
765	     *   [1, new Decimal(10.333)],
766	     *   [2, new Decimal(10.333)],
767	     *   [3, new Decimal(10.334)]
768	     * ]);
769	     * const fairTotals = calculations.final.getPersonFairTotals(receiptTotal, personTotals);
770	     * // Returns: Map([
771	     * //   [1, new Decimal(10.33)],
772	     * //   [2, new Decimal(10.33)],
773	     * //   [3, new Decimal(10.34)]
774	     * // ])
775	     * // Sum: 10.33 + 10.33 + 10.34 = 31.00 ✓
776	     *
777	     * // Example with rounding gap
778	     * // Receipt total: $10.00
779	     * // Person totals: [3.333, 3.333, 3.334] (sum = 10.00)
780	     * // After rounding: [3.33, 3.33, 3.33] (sum = 9.99) - gap of 1 cent
781	     * // Fair totals: [3.33, 3.33, 3.34] (sum = 10.00) - penny goes to person with largest fractional part
782	     * ```
783	     */
784	    export function getPersonFairTotals(
785	      receiptTotal: Decimal,
786	      personTotals: Map<PersonIdentifier, Decimal>
787	    ): Map<PersonIdentifier, Decimal> {
788	      // Step 1: Convert to cents (truncate directly to avoid double-conversion errors)
789	      const inCents = Array.from(personTotals).map(([userId, value]) => ({
790	        userId,
791	        original: value,
792	        cents: new Decimal(value).mul(100).trunc(), // Convert directly to integer cents
793	      }));
794	
795	      // Step 2: Calculate rounding gap in cents
796	      const roundedSumCents = inCents.length
797	        ? Decimal.sum(...inCents.map(({ cents }) => cents))
798	        : new Decimal(0);
799	      const receiptTotalCents = receiptTotal.mul(100).trunc();
800	      let diffCents = receiptTotalCents.minus(roundedSumCents);
801	
802	      // Step 3: Sort by largest fractional part (for fair distribution of pennies)
803	      inCents.sort((a, b) => b.original.mod(1).cmp(a.original.mod(1)));
804	
805	      // Step 4: Distribute the extra pennies by working with integer cents
806	      if (inCents.length > 0) {
807	        let index = 0;
808	        while (!diffCents.isZero()) {
809	          const entry = inCents[index % inCents.length];
810	          entry.cents = entry.cents.plus(diffCents.gt(0) ? 1 : -1); // Add or subtract 1 cent (integer arithmetic)
811	          diffCents = diffCents.plus(diffCents.gt(0) ? -1 : 1);
812	          index++;
813	        }
814	      }
815	
816	      // Step 5: Convert back to dollars and return
817	      const result: Map<PersonIdentifier, Decimal> = new Map(
818	        inCents.map(({ userId, cents }) => [userId, cents.div(100)])
819	      );
820	
821	      return result;
822	    }
823	  }
